css:
.print-format {
    font-family: Arial, sans-serif;
    font-size: 10px;
}

.header {
    text-align: center;
    margin-bottom: 20px;
    border-bottom: 2px solid #333;
    padding-bottom: 15px;
}

.header h1 {
    font-size: 18px;
    margin: 0 0 5px 0;
}

.header h2 {
    font-size: 14px;
    margin: 0 0 10px 0;
    color: #666;
}

.header-info {
    display: flex;
    justify-content: space-between;
    margin-top: 10px;
}

.header-info .label {
    font-weight: bold;
    color: #333;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 15px;
}

th {
    background-color: #333;
    color: white;
    padding: 8px 5px;
    text-align: left;
    font-size: 9px;
}

td {
    padding: 5px;
    border-bottom: 1px solid #ddd;
}

.section-row {
    background-color: #f0f0f0;
    font-weight: bold;
}

.item-row td {
    padding-left: 15px;
}

.wbs-code {
    font-family: monospace;
}

.number {
    text-align: right;
}

.total-row {
    background-color: #333;
    color: white;
    font-weight: bold;
}

.total-row td {
    padding: 10px 5px;
}

.footer {
    margin-top: 30px;
    text-align: center;
    font-size: 8px;
    color: #999;
    border-top: 1px solid #ddd;
    padding-top: 10px;
}
